+                unsafe { *buf.add(count) = ch as c_char };
+                count += 1;
+            }
+            // extract_delim < 0: consume but don't store
+            // extract_delim == 0: put it back
+            if extract_delim == 0 {
+                let _ = unsafe { stdio_abi::ungetc(ch, fp) };
+            }
+            break;
+        }
+        unsafe { *buf.add(count) = ch as c_char };
+        count += 1;
     }
